property.code:
.confluenceMacroDocEdit fieldset.confluenceMacroDocUrl {
  padding: 2ex;
  padding-bottom: 0;
  border: 1px solid var(--legend-border-color, #e5e5e5);
  margin-bottom: 19px;

  dl.confluenceMacroDocPage {
    display: grid;
    grid-template-columns: 70% 30%;
    grid-template-rows: auto auto;
  }
  dd.confluenceMacroDocPageRef {
    grid-column: 1;
  }
  dt.confluenceMacroDocPageAnchor {
    grid-row: 1;
    margin-top:0;
  }
  dd  {
    grid-row: 2;
  }
  .confluenceMacroDocPageAnchor {
    margin-left: 2ex;
    grid-column: 2;
  }

  legend {
    margin-bottom: 0;
    border-bottom: 0;
    width: unset;
    padding: 0 1ex;
  }
}
